// Final formatting: Convert cleaned posts to array format
// Handle both single items and arrays from Clean Post Data
const items = $input.all();

if (!items || items.length === 0) {
  console.warn('⚠️ [Format Response] No items to format, returning empty array');
  return [{ json: [] }];
}

// Extract posts from items
const posts = [];

for (const item of items) {
  const json = item.json || {};

  // If json is already an array, spread it
  if (Array.isArray(json)) {
    posts.push(...json);
  } else if (json.posts && Array.isArray(json.posts)) {
    // If json has a posts property
    posts.push(...json.posts);
  } else if (json.title || json.content || json.link) {
    // Single post object
    posts.push(json);
  }
}

console.log('✅ [Format Response] Formatted posts for response:', posts.length);

// Return as array for Respond with Posts
return posts.map(post => ({ json: post }));

// Format response data for Respond with Like Result
// Get data from Save Like node (updated row) and Prepare Like Update node (postId)
const saveLikeData = $input.first().json;
const prepareData = $('Prepare Like Update').first().json;

// Debug: Log what we received
console.log('📡 [Format Like Response] Save Like data:', JSON.stringify(saveLikeData));
console.log('📡 [Format Like Response] Prepare data:', JSON.stringify(prepareData));

// Check if Save Like node returned empty (update failed)
if (!saveLikeData || Object.keys(saveLikeData).length === 0) {
  console.warn('⚠️ [Format Like Response] Save Like node returned empty, using prepareData');
  // Use prepareData as fallback (optimistic update)
  const likes = parseInt(prepareData.liked || 0, 10) || 0;
  const postId = prepareData.postId || prepareData.row_number || null;

  return [{
    json: {
      success: true,
      likes: likes,
      post_id: postId,
      warning: 'Update may have failed, using optimistic value'
    }
  }];
}

// Extract liked count from updated row
const likes = parseInt(saveLikeData.liked || prepareData.liked || 0, 10) || 0;

// Extract postId from Prepare Like Update node
const postId = prepareData.postId || prepareData.row_number || saveLikeData.postId || saveLikeData.post_id || null;

return [{
  json: {
    success: true,
    likes: likes,
    post_id: postId
  }
}];

// Prepare data for updating liked column
// We need to merge data from two sources:
// 1. Original request (from Check Request Method) - contains postId
// 2. Row data (from Read Blog Row) - contains current liked value

// Get original request data from Check Request Method node
const originalRequest = $('Check Request Method').first().json.body || $('Check Request Method').first().json;
const postId = originalRequest.postId || originalRequest.post_id || originalRequest.rowNumber || originalRequest.row_number;

// Get all rows from Read Blog Row node
const allRows = $input.all();

// Find the row that matches our rowNumber
// Row number 700 means it's the 700th data row (row 701 in sheet, accounting for header)
let targetRow = null;

if (postId) {
  // Try to find row by index (postId should be the row number)
  // The Read Blog Row node returns all rows, so we need to find the one at index (postId - 1)
  const rowIndex = parseInt(postId, 10) - 1; // Convert to 0-based index
  if (rowIndex >= 0 && rowIndex < allRows.length) {
    targetRow = allRows[rowIndex].json;
  } else {
    // Fallback: use first row if index not found
    targetRow = allRows[0]?.json || {};
  }
} else {
  // No postId, use first row
  targetRow = allRows[0]?.json || {};
}

// Extract current liked value and increment/decrement based on unlike flag
const currentLikes = parseInt(targetRow.liked || 0, 10) || 0;
const isUnlike = originalRequest.unlike === true || originalRequest.unlike === 'true';
const newLikes = isUnlike ? Math.max(0, currentLikes - 1) : currentLikes + 1;

// Return data for update node
// We need to provide a matching column value (title) and the updated liked value
// Ensure title is trimmed and matches exactly
const title = (targetRow.title || '').trim();

if (!title) {
  console.error('❌ [Prepare Like Update] No title found for row:', postId);
  return [{
    json: {
      error: 'No title found',
      postId: postId,
      row_number: postId
    }
  }];
}

return [{
  json: {
    title: title, // Use title as matching column (trimmed)
    liked: newLikes.toString(), // Update liked column
    postId: postId,
    row_number: postId
  }
}];

// Extract likes from blog sheet (liked column)
// The blog sheet has columns: title, content, image, isodate, creator, category, link, liked
// We need to map row numbers to liked counts
const likesData = [];

for (const item of $input.all()) {
  // Each row from blog sheet has a liked column
  // Row number is the index (1-based, but we need to account for header row)
  const rowNumber = item.json.__rowNumber || item.json.row_number || (likesData.length + 1);
  const likes = parseInt(item.json.liked || item.json.likes || 0, 10) || 0;

  likesData.push({
    row_number: rowNumber,
    likes: likes
  });
}

return [{ json: { likesData: likesData } }];

// Format and clean blog post data
// Ensure all required fields are present and properly formatted
const items = $input.all();

if (!items || items.length === 0) {
  return [{ json: [] }];
}

const cleanedPosts = items.map((item, index) => {
  const post = item.json || {};

  // Ensure required fields with defaults
  const cleaned = {
    id: post.id || post.row_number || post.__rowNumber || (index + 1),
    row_number: post.row_number || post.__rowNumber || (index + 1),
    title: post.title || 'Untitled',
    content: post.content || post.body || '',
    excerpt: post.excerpt || post.description || '',
    image: post.image || post.thumbnail || '',
    thumbnail: post.thumbnail || post.image || '',
    isodate: post.isodate || post.date || new Date().toISOString(),
    date: post.date || post.isodate || new Date().toISOString(),
    creator: post.creator || post.author || 'Keymoji Team',
    category: post.category || 'uncategorized',
    link: post.link || '',
    slug: post.slug || '',
    likes: parseInt(post.likes || post.liked || 0, 10) || 0,
    liked: post.liked === true || post.liked === 'true' || false
  };

  // Generate slug from title if missing
  if (!cleaned.slug && cleaned.title) {
    cleaned.slug = cleaned.title
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-+|-+$/g, '');
  }

  return { json: cleaned };
});

console.log('✅ [Clean Post Data] Cleaned posts:', cleanedPosts.length);

return cleanedPosts;

// Validate and handle empty data from Google Sheets
// If Google Sheets returns empty or restricted, return empty array
const items = $input.all();

console.log('📊 [Validate Blog Posts] Received items:', items.length);

// Check if we have valid data
if (!items || items.length === 0) {
  console.warn('⚠️ [Validate Blog Posts] No items received from Google Sheets');
  // Return empty array instead of failing
  return [{ json: { posts: [] } }];
}

// Check if first item has error
const firstItem = items[0];
if (firstItem.error || firstItem.json?.error) {
  console.error('❌ [Validate Blog Posts] Error from Google Sheets:', firstItem.error || firstItem.json?.error);
  // Return empty array instead of failing
  return [{ json: { posts: [] } }];
}

// Check if data structure is valid (should have title, content, etc.)
const validItems = items.filter(item => {
  const json = item.json || {};
  // At minimum, should have title or content
  return json.title || json.content || json.link;
});

if (validItems.length === 0) {
  console.warn('⚠️ [Validate Blog Posts] No valid blog posts found in data');
  return [{ json: { posts: [] } }];
}

console.log('✅ [Validate Blog Posts] Valid posts found:', validItems.length);

// Return valid items
return validItems.map(item => ({ json: item.json }));

