// Get A/B test results
const data = $input.first().json;
const abTests = $input.all();
const testName = data.testName;

// Filter tests for this test name
const testResults = abTests.filter(test => test.testName === testName);

// Calculate results by variant
const results = {
  A: { participants: 0, conversions: 0, conversionRate: 0 },
  B: { participants: 0, conversions: 0, conversionRate: 0 }
};

// Aggregate results
for (const test of testResults) {
  const variant = test.variant;
  results[variant].participants++;
  if (test.conversion) {
    results[variant].conversions++;
  }
}

// Calculate conversion rates
for (const variant in results) {
  if (results[variant].participants > 0) {
    results[variant].conversionRate = 
      (results[variant].conversions / results[variant].participants) * 100;
  }
}

return { json: { testName, results } };

// Track A/B test event
const data = $input.first().json;
const abTests = $input.all();
const userId = data.userId;
const testName = data.testName;
const event = data.event;
const conversion = data.conversion;

// Find user's test
const userTest = abTests.find(test => 
  test.userId === userId && test.testName === testName
);

if (!userTest) {
  throw new Error('A/B test not found for user');
}

// Update test with event
const updatedTest = {
  ...userTest,
  conversion: userTest.conversion || conversion,
  events: [...(userTest.events || []), {
    event,
    conversion,
    timestamp: new Date().toISOString()
  }]
};

return { json: updatedTest };

// Assign A/B test variant
const data = $input.first().json;
const abTests = $input.all();
const userId = data.userId;
const testName = data.testName;

// Check if user already has a variant for this test
const existingTest = abTests.find(test => 
  test.userId === userId && test.testName === testName
);

if (existingTest) {
  // User already has a variant
  return { json: { userId, testName, variant: existingTest.variant } };
}

// Assign new variant (A or B)
const variant = Math.random() < 0.5 ? 'A' : 'B';

// Create new test assignment
const newTest = {
  userId,
  testName,
  variant,
  assignedAt: new Date().toISOString(),
  conversion: false,
  events: []
};

return { json: newTest };

