  }
}];

// Validate OTP
const sheetRow = $input.first().json;

let requestData = {};
try {
  requestData = $('Extract Body').first().json;
} catch(e) {
  requestData = sheetRow;
}

const incomingCode = String(requestData.otpCode || '').trim();
const incomingEmail = String(requestData.email || '').trim();

console.log('🔍 Verify OTP for:', incomingEmail, '| code len:', incomingCode.length);
console.log('🔍 Sheet row keys:', Object.keys(sheetRow || {}));
console.log('🔍 otp_code from sheet:', sheetRow?.otp_code);

if (!sheetRow || !sheetRow.email) {
  return [{ json: { success: false, error: 'Kein Account gefunden. Bitte zuerst registrieren.' } }];
}

const storedCode = String(sheetRow.otp_code || '').trim();
const expiresAt  = sheetRow.otp_expires_at || '';

if (!storedCode) {
  return [{ json: { success: false, error: 'Kein Code gefunden. Bitte neuen Code anfordern.' } }];
}
if (storedCode !== incomingCode) {
  return [{ json: { success: false, error: 'Ungültiger Code. Bitte erneut eingeben.' } }];
}
if (expiresAt) {
  const expiry = new Date(expiresAt);
  if (new Date() > expiry) {
    return [{ json: { success: false, error: 'Code abgelaufen. Bitte neuen Code anfordern.' } }];
  }
}

console.log('✅ OTP valid! userId:', sheetRow.userId || 'n/a');
return [{
  json: {
    success: true,
    userId: sheetRow.userId || sheetRow.user_id || null,
    email:  incomingEmail,
    tier:   sheetRow.tier || 'free'
  }
}];

// SMART MERGE: Preserves usageHistory + dailyUsage from Google Sheets!
// Duplicate prevention: always use existing userId if account already exists
const items = $input.all();
const webhookData = $('Extract Body').first().json;
const existingData = items[0]?.json || null;

console.log('📊 Webhook data userId:', webhookData?.userId);
console.log('📊 Existing data found:', !!existingData?.email);

function parseJSON(val, fallback = {}) {
  if (!val) return fallback;
  if (typeof val === 'object') return val;
  try { return JSON.parse(val); } catch { return fallback; }
}

const existingProfile = parseJSON(existingData?.profile, {});
const existingMetadata = parseJSON(existingData?.metadata, {});
const incomingProfile = parseJSON(webhookData.profile, {});
const incomingMetadata = parseJSON(webhookData.metadata, {});

// usageHistory: der längere Array gewinnt (nie Daten verlieren)
const existingUsageHistory = existingMetadata.usageHistory || [];
const incomingUsageHistory = incomingMetadata.usageHistory || [];
const finalUsageHistory = incomingUsageHistory.length > existingUsageHistory.length
  ? incomingUsageHistory
  : existingUsageHistory;

// dailyUsage: incoming gewinnt nur wenn das Datum gleich oder neuer ist
const existingDailyUsage = parseJSON(existingData?.dailyUsage, null);
const incomingDailyUsage = parseJSON(webhookData.dailyUsage, null);
let finalDailyUsage = existingDailyUsage;
if (incomingDailyUsage) {
  if (!existingDailyUsage || incomingDailyUsage.date >= existingDailyUsage.date) {
    finalDailyUsage = incomingDailyUsage;
  }
}

const mergedProfile = { ...existingProfile, ...incomingProfile };
const mergedMetadata = { ...existingMetadata, ...incomingMetadata, usageHistory: finalUsageHistory };

// CRITICAL: Use existing userId to prevent duplicate accounts with same email!
const finalUserId = existingData?.userId || webhookData.userId;
if (existingData?.userId && existingData.userId !== webhookData.userId) {
  console.log('⚠️ Duplicate prevention: using existing userId', existingData.userId, 'instead of', webhookData.userId);
}

// lastLogin: nur setzen wenn vom Client explizit mitgesendet (Login-Event)
// Bei dailyUsage-Updates kommt kein lastLogin → bestehenden Wert beibehalten
const finalLastLogin = webhookData.lastLogin || existingData?.lastLogin || new Date().toISOString();

const output = {
  userId: finalUserId,
  email: webhookData.email,
  tier: webhookData.tier || existingData?.tier || 'free',
  createdAt: existingData?.createdAt || webhookData.createdAt || new Date().toISOString(),
  lastLogin: finalLastLogin,
  profile: JSON.stringify(mergedProfile),
  dailyUsage: finalDailyUsage ? JSON.stringify(finalDailyUsage) : (existingData?.dailyUsage || ''),
  metadata: JSON.stringify(mergedMetadata),
  status: webhookData.status || existingData?.status || 'active'
};

console.log('📤 Output ready for:', output.userId, '| lastLogin updated:', !!webhookData.lastLogin);
return { json: output };

